import { readFile } from "node:fs/promises";
import path from "node:path";
import { ManifestSchema } from "../schemas/manifest.ts";
import { validate } from "../schemas/validate.ts";
import { UserError } from "../errors.ts";
import type { Manifest } from "../types.ts";

export async function loadManifest(directory: string): Promise<Manifest> {
  const manifestPath = path.join(directory, "inception.json");

  let raw: string;
  try {
    raw = await readFile(manifestPath, "utf-8");
  } catch {
    throw new UserError(
      "MANIFEST_INVALID",
      `No inception.json found in ${directory}. Are you pointing to the right repo?`,
    );
  }

  let parsed: unknown;
  try {
    parsed = JSON.parse(raw);
  } catch {
    throw new UserError("MANIFEST_INVALID", `Invalid JSON in ${manifestPath}`);
  }

  return validateManifest(parsed, manifestPath);
}

function formatPath(
  segments: ReadonlyArray<{ readonly key: PropertyKey }> | undefined,
): string {
  if (!segments || segments.length === 0) return "";
  return (
    segments
      .map((seg, i) => {
        if (typeof seg.key === "number") return `[${seg.key}]`;
        return i === 0 ? String(seg.key) : `.${String(seg.key)}`;
      })
      .join("") + " "
  );
}

function validateManifest(data: unknown, filePath: string): Manifest {
  const result = validate(ManifestSchema, data);

  if (result.issues) {
    const issue = result.issues[0];
    const seg0 = issue.path?.[0];

    // Top-level "skills" key missing or wrong type
    if (
      issue.path?.length === 1 &&
      seg0 !== undefined &&
      "key" in seg0 &&
      seg0.key === "skills"
    ) {
      throw new UserError(
        "MANIFEST_INVALID",
        `${filePath}: "skills" must be an array`,
      );
    }

    const prefix = formatPath(
      issue.path as ReadonlyArray<{ readonly key: PropertyKey }> | undefined,
    );
    throw new UserError(
      "MANIFEST_INVALID",
      `${filePath}: ${prefix}${issue.message}`,
    );
  }

  return result.value as Manifest;
}

