   150→
   151→function resolvePlaceholders(
   152→  segments: string[],
   153→  skillName: string,
   154→  home: string,
   155→): string {
   156→  const appdata = process.env.APPDATA ?? path.join(home, "AppData", "Roaming");
   157→  const xdgRaw = process.env.XDG_CONFIG_HOME;
   158→  const xdgConfig =
   159→    xdgRaw && path.isAbsolute(xdgRaw) ? xdgRaw : path.join(home, ".config");
