     1→import { chmod, mkdir, readFile, writeFile } from "node:fs/promises";
     2→import path from "node:path";
     3→import type { AgentId } from "../types.ts";
     4→
     5→const REGISTRY_DIR = ".inception-engine";
     6→const REGISTRY_FILE = "registry.json";
     7→
     8→export interface RegistryEntry {
     9→  source: string;
    10→  skill: string;
    11→  agent: AgentId;
    12→  method: "symlink" | "copy";
    13→  deployed: string;
    14→}
    15→
    16→interface Registry {
    17→  version: 1;
    18→  deployments: Record<string, RegistryEntry>;
    19→}
    20→
    21→export function registryPath(home: string): string {
    22→  return path.join(home, REGISTRY_DIR, REGISTRY_FILE);
    23→}
    24→
    25→async function loadRegistry(home: string): Promise<Registry> {
    26→  try {
    27→    const content = await readFile(registryPath(home), "utf-8");
    28→    const parsed = JSON.parse(content);
    29→    if (
    30→      parsed &&
    31→      typeof parsed === "object" &&
    32→      parsed.version === 1 &&
    33→      parsed.deployments &&
    34→      typeof parsed.deployments === "object"
    35→    ) {
    36→      return parsed as Registry;
    37→    }
    38→    return emptyRegistry();
    39→  } catch {
    40→    return emptyRegistry();
    41→  }
    42→}
    43→
    44→async function saveRegistry(home: string, registry: Registry): Promise<void> {
    45→  const dir = path.join(home, REGISTRY_DIR);
    46→  await mkdir(dir, { recursive: true });
    47→  const filePath = registryPath(home);
    48→  await writeFile(filePath, `${JSON.stringify(registry, null, 2)}\n`);
    49→  await setFilePermissions(filePath);
    50→}
    51→
    52→/**
    53→ * Ensure the file is not world-writable regardless of umask.
    54→ * On Windows, the OS inherits ACLs from the parent directory — no-op is correct.
    55→ */
    56→async function setFilePermissions(filePath: string): Promise<void> {
    57→  if (process.platform !== "win32") {
    58→    await chmod(filePath, 0o644);
    59→  }
    60→}
    61→
    62→function emptyRegistry(): Registry {
    63→  return { version: 1, deployments: {} };
    64→}
    65→
    66→export async function registerDeployment(
    67→  home: string,
    68→  targetPath: string,
    69→  entry: Omit<RegistryEntry, "deployed">,
    70→): Promise<void> {
    71→  const registry = await loadRegistry(home);
    72→  registry.deployments[targetPath] = {
    73→    ...entry,
    74→    deployed: new Date().toISOString(),
    75→  };
    76→  await saveRegistry(home, registry);
    77→}
    78→
    79→export async function unregisterDeployment(
    80→  home: string,
    81→  targetPath: string,
    82→): Promise<void> {
    83→  const registry = await loadRegistry(home);
    84→  if (!(targetPath in registry.deployments)) return;
    85→  delete registry.deployments[targetPath];
    86→  await saveRegistry(home, registry);
    87→}
    88→
    89→export async function lookupDeployment(
    90→  home: string,
    91→  targetPath: string,
    92→): Promise<RegistryEntry | null> {
    93→  const registry = await loadRegistry(home);
    94→  return registry.deployments[targetPath] ?? null;
    95→}
    96→
    97→export async function verifyDeployment(
    98→  home: string,
    99→  targetPath: string,
   100→  expected: { source: string; skill: string; agent: AgentId },
   101→): Promise<RegistryEntry | null> {
   102→  const entry = await lookupDeployment(home, targetPath);
   103→  if (!entry) return null;
   104→  if (
   105→    entry.source !== expected.source ||
   106→    entry.skill !== expected.skill ||
   107→    entry.agent !== expected.agent
   108→  ) {
   109→    return null;
   110→  }
   111→  return entry;
   112→}
