- Remove `formatPath` (use `formatZodPath` from `schemas/errors.ts`)
- Remove `import type { Manifest }` (no longer needed; type flows from `safeParse`)
- Add enum error handling so the test `/unknown agent "unknown-agent"/` keeps passing:

```ts
import { formatZodPath } from "../schemas/errors.ts";
import { AGENT_IDS } from "../types.ts";

// in validateManifest:
const issue = result.error.issues[0];
const path = issue.path as (string | number)[];

// top-level "skills" missing/wrong type
if (path.length === 1 && path[0] === "skills") {
  throw new UserError("MANIFEST_INVALID", `${filePath}: "skills" must be an array`);
}

// enum failure on agent ID
if (issue.code === "invalid_enum_value" && typeof issue.received === "string") {
  const prefix = formatZodPath(path);
  throw new UserError(
    "MANIFEST_INVALID",
    `${filePath}: ${prefix}unknown agent "${issue.received}". Valid agents: ${AGENT_IDS.join(", ")}`,
  );
}

const prefix = formatZodPath(path);
throw new UserError("MANIFEST_INVALID", `${filePath}: ${prefix}${issue.message}`);
```

The `return result.data as Manifest` cast becomes `return result.data` since `z.infer<typeof ManifestSchema>` now equals `Manifest`.

### 6. `src/core/ownership.ts` — remove hand-maintained interfaces

Remove the `RegistryEntry` interface and `Registry` interface; import derived types from schemas:

```ts
import type { Registry, RegistryEntry } from "../schemas/registry.ts";
```

Remove `AgentId` import (it flows through `RegistryEntry` from the schema now).
The `result.data as Registry` cast disappears.

`RegistryEntry` is exported from `ownership.ts` today. Change to re-export from schemas:
```ts
export type { RegistryEntry } from "../schemas/registry.ts";
```

### 7. `src/index.ts` — collapse split+loop+cast into one `.map()`

```ts
agents = values.agents
  .split(",")
  .map((s) => s.trim())
  .map((id) => {
    const r = AgentIdSchema.safeParse(id);
    if (!r.success) {
      throw new UserError(
        "INVALID_ARGS",
        `Unknown agent: "${id}". Valid agents: ${AGENT_IDS.join(", ")}`,
      );
    }
    return r.data;  // AgentId — no cast
  });
```

Remove the `validate` import from `schemas/validate.ts` (no longer needed in `index.ts`).

---

## Critical Files

| File | Change |
|---|---|
| `src/schemas/manifest.ts` | Move `AGENT_IDS` here; switch to `z.enum()`; export derived types |
| `src/schemas/registry.ts` | Export derived types |
| `src/schemas/errors.ts` | New — `formatZodPath` helper |
| `src/types.ts` | Re-export `AgentId`, `AGENT_IDS`, `Manifest`, `SkillEntry` from schemas |
| `src/config/manifest.ts` | Use `formatZodPath`; handle `invalid_enum_value`; remove `as Manifest` cast |
| `src/core/ownership.ts` | Remove hand interfaces; import types from schemas; remove `as Registry` cast |
| `src/index.ts` | Collapse agent list parsing to typed `.map()`; remove `validate` import |

