import { readFile } from "node:fs/promises";
import path from "node:path";
import { formatZodPath } from "../schemas/errors.ts";
import { AGENT_IDS, ManifestSchema } from "../schemas/manifest.ts";
import type { Manifest } from "../schemas/manifest.ts";
import { UserError } from "../errors.ts";

export async function loadManifest(directory: string): Promise<Manifest> {
  const manifestPath = path.join(directory, "inception.json");

  let raw: string;
  try {
    raw = await readFile(manifestPath, "utf-8");
  } catch {
    throw new UserError(
      "MANIFEST_INVALID",
      `No inception.json found in ${directory}. Are you pointing to the right repo?`,
    );
  }

  let parsed: unknown;
  try {
    parsed = JSON.parse(raw);
  } catch {
    throw new UserError("MANIFEST_INVALID", `Invalid JSON in ${manifestPath}`);
  }

  return validateManifest(parsed, manifestPath);
}

function validateManifest(data: unknown, filePath: string): Manifest {
  const result = ManifestSchema.safeParse(data);

  if (!result.success) {
    const issue = result.error.issues[0];
    const issuePath = issue.path as (string | number)[];

    // Top-level "skills" key: missing or wrong type → uniform message
    if (issuePath.length === 1 && issuePath[0] === "skills") {
      throw new UserError(
        "MANIFEST_INVALID",
        `${filePath}: "skills" must be an array`,
      );
    }

    // Enum failure on agent ID — detected by path pattern (agents[N]) rather than
    // issue code, which varies across Zod versions.
    const prevSeg = issuePath.at(-2);
    const lastSeg = issuePath.at(-1);
    if (prevSeg === "agents" && typeof lastSeg === "number") {
      const received = typeof (issue as { input?: unknown }).input === "string"
        ? (issue as { input: string }).input
        : "";
      const prefix = formatZodPath(issuePath);
      throw new UserError(
        "MANIFEST_INVALID",
        `${filePath}: ${prefix}unknown agent "${received}". Valid agents: ${AGENT_IDS.join(", ")}`,
      );
    }

    throw new UserError(
      "MANIFEST_INVALID",
      `${filePath}: ${formatZodPath(issuePath)}${issue.message}`,
    );
  }

  return result.data;
}

