     1→import { readFile } from "node:fs/promises";
     2→import path from "node:path";
     3→import { ManifestSchema } from "../schemas/manifest.ts";
     4→import { UserError } from "../errors.ts";
     5→import type { Manifest } from "../types.ts";
     6→
     7→export async function loadManifest(directory: string): Promise<Manifest> {
     8→  const manifestPath = path.join(directory, "inception.json");
     9→
    10→  let raw: string;
    11→  try {
    12→    raw = await readFile(manifestPath, "utf-8");
    13→  } catch {
    14→    throw new UserError(
    15→      "MANIFEST_INVALID",
    16→      `No inception.json found in ${directory}. Are you pointing to the right repo?`,
    17→    );
    18→  }
    19→
    20→  let parsed: unknown;
    21→  try {
    22→    parsed = JSON.parse(raw);
    23→  } catch {
    24→    throw new UserError("MANIFEST_INVALID", `Invalid JSON in ${manifestPath}`);
    25→  }
    26→
    27→  return validateManifest(parsed, manifestPath);
    28→}
    29→
    30→function formatPath(segments: (string | number)[]): string {
    31→  if (segments.length === 0) return "";
    32→  return `${segments
    33→    .map((seg, i) => {
    34→      if (typeof seg === "number") return `[${seg}]`;
    35→      return i === 0 ? seg : `.${seg}`;
    36→    })
    37→    .join("")} `;
    38→}
    39→
    40→function validateManifest(data: unknown, filePath: string): Manifest {
    41→  const result = ManifestSchema.safeParse(data);
    42→
    43→  if (!result.success) {
    44→    const issue = result.error.issues[0];
    45→
    46→    // Top-level "skills" key: missing or wrong type → uniform message
    47→    if (issue.path.length === 1 && issue.path[0] === "skills") {
    48→      throw new UserError(
    49→        "MANIFEST_INVALID",
    50→        `${filePath}: "skills" must be an array`,
    51→      );
    52→    }
    53→
    54→    const prefix = formatPath(issue.path as (string | number)[]);
    55→    throw new UserError(
    56→      "MANIFEST_INVALID",
    57→      `${filePath}: ${prefix}${issue.message}`,
    58→    );
    59→  }
    60→
    61→  return result.data as Manifest;
    62→}
    63→

