     1→import { chmod, mkdir, readFile, writeFile } from "node:fs/promises";
     2→import path from "node:path";
     3→import { RegistrySchema } from "../schemas/registry.ts";
     4→import type { AgentId } from "../types.ts";
     5→
     6→const REGISTRY_DIR = ".inception-engine";
     7→const REGISTRY_FILE = "registry.json";
     8→
     9→export interface RegistryEntry {
    10→  source: string;
    11→  skill: string;
    12→  agent: AgentId;
    13→  method: "symlink" | "copy";
    14→  deployed: string;
    15→}
    16→
    17→interface Registry {
    18→  version: 1;
    19→  deployments: Record<string, RegistryEntry>;
    20→}
    21→
    22→export function registryPath(home: string): string {
    23→  return path.join(home, REGISTRY_DIR, REGISTRY_FILE);
    24→}
    25→
    26→async function loadRegistry(home: string): Promise<Registry> {
    27→  try {
    28→    const content = await readFile(registryPath(home), "utf-8");
    29→    const parsed = JSON.parse(content);
    30→    const result = RegistrySchema.safeParse(parsed);
    31→    return result.success ? (result.data as Registry) : emptyRegistry();
    32→  } catch {
    33→    return emptyRegistry();
    34→  }
    35→}
    36→
    37→async function saveRegistry(home: string, registry: Registry): Promise<void> {
    38→  const dir = path.join(home, REGISTRY_DIR);
    39→  await mkdir(dir, { recursive: true });
    40→  const filePath = registryPath(home);
    41→  await writeFile(filePath, `${JSON.stringify(registry, null, 2)}\n`);
    42→  await setFilePermissions(filePath);
    43→}
    44→
    45→/**
    46→ * Ensure the file is not world-writable regardless of umask.
    47→ * On Windows, the OS inherits ACLs from the parent directory — no-op is correct.
    48→ */
    49→async function setFilePermissions(filePath: string): Promise<void> {
    50→  if (process.platform !== "win32") {
    51→    await chmod(filePath, 0o644);
    52→  }
    53→}
    54→
    55→function emptyRegistry(): Registry {
    56→  return { version: 1, deployments: {} };
    57→}
    58→
    59→export async function registerDeployment(
    60→  home: string,
    61→  targetPath: string,
    62→  entry: Omit<RegistryEntry, "deployed">,
    63→): Promise<void> {
    64→  const registry = await loadRegistry(home);
    65→  registry.deployments[targetPath] = {
    66→    ...entry,
    67→    deployed: new Date().toISOString(),
    68→  };
    69→  await saveRegistry(home, registry);
    70→}
    71→
    72→export async function unregisterDeployment(
    73→  home: string,
    74→  targetPath: string,
    75→): Promise<void> {
    76→  const registry = await loadRegistry(home);
    77→  if (!(targetPath in registry.deployments)) return;
    78→  delete registry.deployments[targetPath];
    79→  await saveRegistry(home, registry);
    80→}
    81→
    82→export async function lookupDeployment(
    83→  home: string,
    84→  targetPath: string,
    85→): Promise<RegistryEntry | null> {
    86→  const registry = await loadRegistry(home);
    87→  return registry.deployments[targetPath] ?? null;
    88→}
    89→
    90→export async function verifyDeployment(
    91→  home: string,
    92→  targetPath: string,
    93→  expected: { source: string; skill: string; agent: AgentId },
    94→): Promise<RegistryEntry | null> {
    95→  const entry = await lookupDeployment(home, targetPath);
    96→  if (!entry) return null;
    97→  if (
    98→    entry.source !== expected.source ||
    99→    entry.skill !== expected.skill ||
   100→    entry.agent !== expected.agent
   101→  ) {
   102→    return null;
   103→  }
   104→  return entry;
   105→}
