     1→#!/usr/bin/env node
     2→
     3→import path from "node:path";
     4→import { parseArgs } from "node:util";
     5→import { AGENT_REGISTRY } from "./config/agents.ts";
     6→import { loadManifest } from "./config/manifest.ts";
     7→import { executeDeploy, planDeploy } from "./core/deploy.ts";
     8→import { detectInstalledAgents } from "./core/detect.ts";
     9→import { resolveHome } from "./core/resolve.ts";
    10→import { executeRevert, planRevert, planRevertAll } from "./core/revert.ts";
    11→import type { ErrorCode } from "./errors.ts";
    12→import { UserError } from "./errors.ts";
    13→import { dryRunPrefix, logger } from "./logger.ts";
    14→import { AgentIdSchema } from "./schemas/manifest.ts";
    15→import { validate } from "./schemas/validate.ts";
    16→import type { AgentId, CliOptions, Manifest } from "./types.ts";
    17→import { AGENT_IDS } from "./types.ts";
    18→
    19→const USAGE = `
    20→inception-engine - Deploy AI agent skills
    21→
    22→Usage:
    23→  inception-engine <directory> [options]
    24→  inception-engine revert <directory> [options]
    25→
    26→Options:
    27→  --dry-run        Show what would be done without doing it
    28→  --agents <list>  Comma-separated list of agent IDs to target
    29→  --verbose        Show detailed output
    30→  --debug          Show full error stack traces
    31→  --help           Show this help message
    32→
    33→Supported agents:
    34→  ${AGENT_REGISTRY.map((a) => `${a.id} (${a.displayName})`).join(", ")}
    35→`.trim();
    36→
    37→function parseCLI(argv: string[]): CliOptions {
    38→  const args = argv.slice(2);
    39→
    40→  if (args.length === 0) {
    41→    return {
    42→      command: "help",
    43→      directory: "",
    44→      dryRun: false,
    45→      agents: null,
    46→      verbose: false,
    47→      debug: false,
    48→    };
    49→  }
    50→
    51→  let parsed: ReturnType<typeof parseArgs>;
    52→  try {
    53→    parsed = parseArgs({
    54→      args,
    55→      allowPositionals: true,
    56→      options: {
    57→        "dry-run": { type: "boolean", default: false },
    58→        verbose: { type: "boolean", default: false },
    59→        debug: { type: "boolean", default: false },
    60→        help: { type: "boolean", default: false },
    61→        agents: { type: "string" },
    62→      },
    63→    });
    64→  } catch (err) {
    65→    throw new UserError("INVALID_ARGS", (err as Error).message);
    66→  }
    67→
    68→  const { values, positionals } = parsed;
    69→
    70→  if (values.help) {
    71→    return {
    72→      command: "help",
    73→      directory: "",
    74→      dryRun: false,
    75→      agents: null,
    76→      verbose: false,
    77→      debug: false,
    78→    };
    79→  }
    80→
    81→  let command: "deploy" | "revert" = "deploy";
    82→  let pos = positionals;
    83→  if (pos[0] === "revert") {
    84→    command = "revert";
    85→    pos = pos.slice(1);
    86→  }
    87→
    88→  if (pos.length > 1) {
    89→    throw new UserError("INVALID_ARGS", `Unexpected argument: ${pos[1]}`);
    90→  }
    91→  const rawDir = pos[0];
    92→  if (!rawDir) {
    93→    throw new UserError(
    94→      "INVALID_ARGS",
    95→      "Missing required <directory> argument",
    96→    );
    97→  }
    98→
    99→  let agents: AgentId[] | null = null;
   100→  if (typeof values.agents === "string") {
   101→    const ids = values.agents.split(",").map((s) => s.trim());
   102→    for (const id of ids) {
   103→      const r = validate(AgentIdSchema, id);
   104→      if (r.issues) {
   105→        throw new UserError(
   106→          "INVALID_ARGS",
   107→          `Unknown agent: "${id}". Valid agents: ${AGENT_IDS.join(", ")}`,
   108→        );
   109→      }
   110→    }
   111→    agents = ids as AgentId[];
   112→  }
   113→
   114→  return {
   115→    command,
   116→    directory: path.resolve(rawDir),
   117→    dryRun: values["dry-run"] as boolean,
   118→    agents,
   119→    verbose: values.verbose as boolean,
   120→    debug: values.debug as boolean,
   121→  };
   122→}
   123→
   124→async function main(): Promise<number> {
   125→  const options = parseCLI(process.argv);
   126→
   127→  if (options.command === "help") {
   128→    console.log(USAGE);
   129→    return 0;
   130→  }
   131→
   132→  const manifest = await loadManifest(options.directory);
   133→  const home = resolveHome();
   134→
   135→  if (options.command === "deploy") {
   136→    return runDeploy(options, manifest, home);
   137→  }
   138→  return runRevert(options, manifest, home);
   139→}
   140→
   141→async function runDeploy(
   142→  options: CliOptions,
   143→  manifest: Manifest,
   144→  home: string,
   145→): Promise<number> {
   146→  let detectedAgents: AgentId[];
   147→  if (options.agents) {
   148→    detectedAgents = options.agents;
   149→    if (options.verbose) {
   150→      logger.info(`Using specified agents: ${detectedAgents.join(", ")}`);
   151→    }
   152→  } else {
   153→    detectedAgents = await detectInstalledAgents(home);
   154→    if (detectedAgents.length === 0) {
   155→      logger.info("No supported AI agents detected on this system.");
   156→      logger.info(
   157→        `Install one of: ${AGENT_REGISTRY.map((a) => a.displayName).join(", ")}`,
   158→      );
   159→      return 0;
   160→    }
   161→    if (options.verbose) {
   162→      logger.info(`Detected agents: ${detectedAgents.join(", ")}`);
   163→    }
   164→  }
   165→
   166→  const actions = await planDeploy(
   167→    manifest,
   168→    options.directory,
   169→    detectedAgents,
   170→    home,
   171→  );
   172→  if (actions.length === 0) {
   173→    logger.info("No skills to deploy for detected agents.");
   174→    return 0;
   175→  }
   176→
   177→  logger.info(
   178→    `${dryRunPrefix(options.dryRun)}Deploying ${actions.length} skill(s):`,
   179→  );
   180→  const { succeeded, failed } = await executeDeploy(
   181→    actions,
   182→    options.dryRun,
   183→    options.verbose,
   184→    home,
   185→  );
   186→
   187→  logger.info("");
   188→  if (failed.length > 0) {
   189→    logger.info(`${succeeded} succeeded, ${failed.length} failed`);
   190→    return 1;
   191→  }
   192→  logger.info(
   193→    `${succeeded} skill(s) deployed${options.dryRun ? " (dry-run)" : ""}`,
   194→  );
   195→  return 0;
   196→}
   197→
   198→async function runRevert(
   199→  options: CliOptions,
   200→  manifest: Manifest,
   201→  home: string,
   202→): Promise<number> {
   203→  const actions = options.agents
   204→    ? planRevert(manifest, options.agents, home)
   205→    : planRevertAll(manifest, home);
   206→  if (actions.length === 0) {
   207→    logger.info("No skills to revert.");
   208→    return 0;
   209→  }
   210→
   211→  logger.info(
   212→    `${dryRunPrefix(options.dryRun)}Reverting ${actions.length} skill(s):`,
   213→  );
   214→  const { succeeded, skipped } = await executeRevert(
   215→    actions,
   216→    options.dryRun,
   217→    options.verbose,
   218→    home,
   219→  );
   220→
   221→  logger.info("");
   222→  const parts = [`${succeeded} removed`];
   223→  if (skipped > 0) parts.push(`${skipped} skipped`);
   224→  logger.info(`${parts.join(", ")}${options.dryRun ? " (dry-run)" : ""}`);
   225→  return 0;
   226→}
   227→
   228→const USER_ERROR_EXIT: Record<ErrorCode, number> = {
   229→  INVALID_ARGS: 2,
   230→  MANIFEST_INVALID: 3,
   231→  DEPLOY_FAILED: 1,
   232→  RESOLVE_FAILED: 1,
   233→};
   234→
   235→const debugMode = process.argv.includes("--debug");
   236→
   237→try {
   238→  process.exit(await main());
   239→} catch (err) {
   240→  if (err instanceof UserError) {
   241→    logger.error(`Error: ${err.message}`);
   242→    if (debugMode) {
   243→      logger.errorRaw(err);
   244→    }
   245→    process.exit(USER_ERROR_EXIT[err.code]);
   246→  } else {
   247→    logger.error("Unexpected error. Run with --debug for details.");
   248→    if (debugMode) {
   249→      logger.errorRaw(err);
   250→    }
   251→    process.exit(1);
   252→  }
   253→}
   254→

